using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Coordenador de boss multi-parte (Enemy Creator — Etapa 8.3; GDD 12.3:
/// bosses com fases e partes destrutíveis).
///
/// Modelo: o corpo principal é um EnemyController normal (categoria MiniBoss)
/// e cada parte destrutível é OUTRO EnemyController (+EnemyHealth) filho, com
/// o seu próprio EnemyData (vida/fraquezas próprias). Este componente, no
/// corpo principal, observa as partes:
///
/// - "onPartDefeated" dispara quando cada parte morre/desactiva (com o nº de
///   partes ainda vivas) — útil para avançar fases.
/// - "phaseVariableName": escreve o nº de partes destruídas numa variável
///   global INT (GameVariables) — fases podem ser lidas por diálogos,
///   ataques condicionais, etc.
/// - "onAllPartsDefeated" dispara quando todas as partes caem.
/// - "killMainWhenAllPartsDown": derrota o corpo principal automaticamente.
///
/// Janela de vulnerabilidade (GDD: "só toma dano sob certa condição"): no
/// EnemyHealth do corpo principal, adiciona Condition_BossPartsDestroyed às
/// "vulnerabilityConditions" — o corpo só fica vulnerável quando X partes
/// tiverem sido destruídas (ou usa qualquer outra EnemyCondition, ex: variável
/// global de puzzle resolvido).
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyMultiPartBoss : MonoBehaviour
{
    [Header("Partes Destrutíveis (Etapa 8.3)")]
    [Tooltip("EnemyControllers das partes (normalmente filhos deste GameObject). Cada parte tem o seu próprio EnemyData/EnemyHealth.")]
    public List<EnemyController> parts = new List<EnemyController>();

    [Header("Fases (opcional)")]
    [Tooltip("Variável global INT (GameVariables) onde é escrito o nº de partes destruídas (0..N) — usável como nº de fase. Vazio = não escreve.")]
    public string phaseVariableName = "";

    [Header("Fim")]
    [Tooltip("Quando todas as partes caem, derrota o corpo principal automaticamente (EnemyHealth.Kill).")]
    public bool killMainWhenAllPartsDown = false;

    [Header("Eventos")]
    [Tooltip("Disparado quando uma parte é derrotada (parâmetro: nº de partes ainda vivas).")]
    public UnityEvent<int> onPartDefeated;

    public UnityEvent onAllPartsDefeated;

    private EnemyController _controller;
    private readonly HashSet<EnemyController> _defeated = new HashSet<EnemyController>();

    /// <summary>Nº de partes destruídas até agora.</summary>
    public int DefeatedPartCount => _defeated.Count;

    /// <summary>Nº de partes ainda vivas.</summary>
    public int AlivePartCount => Mathf.Max(0, ValidPartCount() - _defeated.Count);

    /// <summary>True se todas as partes registadas foram derrotadas.</summary>
    public bool AllPartsDefeated => ValidPartCount() > 0 && _defeated.Count >= ValidPartCount();

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
    }

    private void OnEnable()
    {
        foreach (var part in parts)
        {
            if (part == null) continue;
            part.OnStateChanged += HandlePartStateChanged;

            // Apanha partes que já estavam derrotadas (ex: ordem de OnEnable).
            if (part.IsTerminal) _defeated.Add(part);
        }

        WritePhaseVariable();
    }

    private void OnDisable()
    {
        foreach (var part in parts)
        {
            if (part != null) part.OnStateChanged -= HandlePartStateChanged;
        }
    }

    private void HandlePartStateChanged(EnemyState oldState, EnemyState newState)
    {
        if (newState != EnemyState.Morto && newState != EnemyState.Desactivado) return;

        // Identifica qual parte mudou (re-varre — listas de partes são pequenas).
        bool changed = false;
        foreach (var part in parts)
        {
            if (part != null && part.IsTerminal && _defeated.Add(part))
                changed = true;
        }

        if (!changed) return;

        WritePhaseVariable();
        onPartDefeated?.Invoke(AlivePartCount);

        if (AllPartsDefeated)
        {
            onAllPartsDefeated?.Invoke();

            if (killMainWhenAllPartsDown)
            {
                var health = _controller.GetEnemyComponent<EnemyHealth>();
                if (health != null) health.Kill();
                else _controller.SetState(EnemyState.Morto);
            }
        }
    }

    private void WritePhaseVariable()
    {
        if (!string.IsNullOrEmpty(phaseVariableName) && GameVariables.Instance != null)
            GameVariables.Instance.SetInt(phaseVariableName, _defeated.Count);
    }

    private int ValidPartCount()
    {
        int count = 0;
        foreach (var part in parts)
            if (part != null) count++;
        return count;
    }

    /// <summary>Reset das partes e do registo (respawn de boss — usar com EnemyRespawn/EnemyPuzzleInteraction.ResetEnemy em cada parte).</summary>
    public void ResetParts()
    {
        _defeated.Clear();
        WritePhaseVariable();
    }
}

/// <summary>
/// Condição (EnemyCondition — composável nas "vulnerabilityConditions" do
/// EnemyHealth ou nas "deactivationConditions" do EnemyController): cumpre-se
/// quando o EnemyMultiPartBoss deste inimigo tem pelo menos
/// "minPartsDestroyed" partes destruídas (Etapa 8.3 — "vulnerável quando as
/// partes caírem"). 0 = todas as partes.
/// </summary>
[System.Serializable]
public class Condition_BossPartsDestroyed : EnemyCondition
{
    [Tooltip("Nº mínimo de partes destruídas para a condição se cumprir. 0 = TODAS as partes.")]
    [Min(0)] public int minPartsDestroyed = 0;

    public override bool Evaluate(EnemyController enemy)
    {
        var boss = enemy != null ? enemy.GetComponent<EnemyMultiPartBoss>() : null;
        if (boss == null) return false;

        if (minPartsDestroyed <= 0) return boss.AllPartsDefeated;
        return boss.DefeatedPartCount >= minPartsDestroyed;
    }
}
